#include<bits/stdc++.h>
using namespace std;
#define int long long

struct Edge
{
	int v, w;
};

vector<Edge> e[1000005];
int fa[1000005], siz[1000005], ans, n;

void dfs(int x, int f)
{
	fa[x] = f;
	for(auto [v, w] : e[x])
	{
		if(v != f) 
		{
			dfs(v, x);
			siz[x] += siz[v];
		}
	}
	siz[x]++;
}

void dfs2(int u)
{
	for(auto [v, w] : e[u])
	{
		if(v != fa[u])
		{
			ans += w * abs(n - siz[v] - siz[v]);
			dfs2(v);
		}
	}
}

signed main()
{
	cin >> n;
	for(int i = 1; i < n; i++)
	{
		int x, y, c;
		cin >> x >> y >> c;
		e[x].push_back({y, c});
		e[y].push_back({x, c});
	}
	dfs(1, 0);
	dfs2(1);
	cout << ans;
}
